insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('a6153068-1e7a-57c4-abd7-9964d3149a15', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'hero', 0, 'home_hero', '{"type":"home_hero","_v":1,"title":"Tout votre cabinet dans\nune seule application","lead":"Le logiciel complet de gestion pour podologues,\npour vous faire gagner du temps au quotidien.","demoCta":{"label":"Voir la démo","href":"/contact"},"priceCta":{"label":"abonnement","amount":"24,84 €","note":"/mois · tout inclus","href":"/tarifs"},"proof":{"count":1000,"prefix":"+","label":"podologues équipés","avatars":[{"mediaId":null,"path":"/images/avatars/av1.jpg","alt":"Podologue équipé 1"},{"mediaId":null,"path":"/images/avatars/av2.jpg","alt":"Podologue équipé 2"},{"mediaId":null,"path":"/images/avatars/av3.jpg","alt":"Podologue équipé 3"},{"mediaId":null,"path":"/images/avatars/av4.jpg","alt":"Podologue équipé 4"},{"mediaId":null,"path":"/images/avatars/av5.jpg","alt":"Podologue équipé 5"},{"mediaId":null,"path":"/images/avatars/av6.jpg","alt":"Podologue équipé 6"},{"mediaId":null,"path":"/images/avatars/av7.jpg","alt":"Podologue équipé 7"},{"mediaId":null,"path":"/images/avatars/av8.jpg","alt":"Podologue équipé 8"}]},"photos":{"back":{"mediaId":null,"path":"/images/hero-femme.png","alt":"Podologue"},"front":{"mediaId":null,"path":"/images/hero-praticien.png","alt":"Praticien souriant utilisant MediCare Pro"}},"infoBar":{"items":[{"icon":"Phone","title":"Téléphone","value":"01 23 45 67 89"},{"icon":"Headset","title":"Support","value":"7j/7 par chat"},{"icon":"MapPin","title":"Hébergement","value":"HDS · France"}],"cta":{"label":"Je m''abonne","href":"app:register:annual"}}}'::jsonb),
  ('c0625d4f-1e65-51b7-80ae-4acacb551d6d', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'bento', 1, 'bento', '{"type":"bento","_v":1,"kicker":"Pourquoi MediCare Pro","title":"L''essentiel, en un coup d''œil","lead":"Un seul outil remplace votre agenda, votre facturation, vos bilans et votre comptabilité.","mockup":{"kicker":"Agenda & RDV en ligne","title":"Vos patients réservent seuls, l''agenda se remplit","kind":"agenda"},"counters":[{"icon":"Wallet","to":260,"prefix":"−","suffix":" €","label":"économisés chaque mois face aux outils séparés"},{"icon":"FileText","to":13,"label":"bilans podologiques normés, scores calculés automatiquement"},{"icon":"Zap","to":100,"suffix":" %","label":"de la facturation générée automatiquement, sans ressaisie"}],"hds":{"icon":"ShieldCheck","title":"Hébergé en France","sub":"HDS · RGPD · chiffré"}}'::jsonb),
  ('8ef4be27-4c37-525c-a55d-d639bad375ad', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'feature_scroll', 2, 'feature_scroll', '{"type":"feature_scroll","_v":1,"kicker":"Tout votre cabinet","title":"Une fonctionnalité pour chaque besoin","limit":6}'::jsonb),
  ('69f1dcfc-8f6a-5638-b003-bfc071f215f5', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'manifesto', 3, 'manifesto', '{"type":"manifesto","_v":1,"kicker":"Notre mission","title":"Moins d''administratif.\nPlus de podologie.","text":"MediCare Pro est né dans un cabinet, pas dans un open space. Chaque fonctionnalité répond à un vrai besoin du quotidien — conçu par des podologues, pour des podologues.","link":{"label":"Découvrir notre histoire","href":"/a-propos"}}'::jsonb),
  ('a65eab03-61f7-555c-a225-c3227f659ad6', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'reviews', 4, 'reviews', '{"type":"reviews","_v":1,"kicker":"Avis de podologues","title":"Ils nous font confiance","tone":"soft","rating":{"value":"4,9/5","label":"note moyenne · podologues abonnés"}}'::jsonb),
  ('e400d3b3-3d73-5ffe-901e-bd27c2f65d62', 'ab84de6e-e4e6-5026-83dc-0c7ddb5be35e', 'cta', 5, 'cta_panel', '{"type":"cta_panel","_v":1,"kicker":"Prêt à simplifier votre cabinet ?","title":"Tout votre cabinet réuni, pour 24,84 €/mois","lead":"Tout-en-un, sans option cachée — et plus de 3 000 € économisés par an en moyenne face aux outils séparés.","primary":{"label":"Je m''abonne","href":"app:register:annual"},"secondary":{"label":"Demander une démo","href":"/contact"},"trust":[{"icon":"ShieldCheck","label":"Hébergé en France (HDS)"},{"icon":"Wallet","label":"Sans engagement"},{"icon":"Clock","label":"Opérationnel en 1 jour"}]}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('33a19f56-12c0-548f-862b-8cfcec9c2c4f', 'e2cadf33-188b-57eb-a9a6-32bf5c50b686', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Fonctionnalités","title":"Tout votre cabinet,\n**automatisé.**","lead":"Facturation, signature, comptabilité, agenda, bilans et application mobile.\nSix outils premium réunis, à partir de 24,84 €/mois."}'::jsonb),
  ('03e0869e-e052-52d8-bc5f-7bf6c5e25cfe', 'e2cadf33-188b-57eb-a9a6-32bf5c50b686', 'showcase', 1, 'feature_showcase', '{"type":"feature_showcase","_v":1,"collection":"features","tones":["white","soft","medium","dark","white","soft","medium","dark","white","soft"],"backgrounds":[{"index":3,"image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-1.jpg","alt":""}},{"index":7,"image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-4.jpg","alt":""}}]}'::jsonb),
  ('e9386459-a845-58ab-b646-568bdf22a9be', 'e2cadf33-188b-57eb-a9a6-32bf5c50b686', 'stats', 2, 'stats_band', '{"type":"stats_band","_v":1,"kicker":"En chiffres","title":"Un seul outil, tout votre cabinet","stats":[{"icon":"Grid","to":10,"suffix":"","label":"fonctionnalités majeures incluses"},{"icon":"FileText","to":13,"suffix":"","label":"bilans podologiques inclus"},{"icon":"Calculator","to":260,"prefix":"−","suffix":" €","label":"par mois vs outils séparés"},{"icon":"Refresh","to":100,"suffix":" %","label":"automatique, sans ressaisie"}]}'::jsonb),
  ('385c74be-4251-5fab-a7fd-a8c0bc7b0b41', 'e2cadf33-188b-57eb-a9a6-32bf5c50b686', 'portal', 3, 'portal_cards', '{"type":"portal_cards","_v":1,"kicker":"Explorer en détail","title":"Tout ce que MediCare Pro vous apporte","linkLabel":"Découvrir","cards":[{"icon":"FileText","title":"Bilans podologiques","text":"13 bilans normés avec scores calculés automatiquement : diabétique, risque de chute, posturologie et plus.","href":"/bilans"},{"icon":"ShieldCheck","title":"Sécurité & conformité","text":"Hébergement HDS en France, conformité RGPD, chiffrement et sauvegardes quotidiennes de vos données patients.","href":"/securite"},{"icon":"CheckCircle","title":"Les avantages","text":"Simplicité, tout-en-un, gain de temps : pourquoi les podologues choisissent MediCare Pro au quotidien.","href":"/avantages"}]}'::jsonb),
  ('49d3d8b9-5f03-53be-9a3f-33a9ce62743b', 'e2cadf33-188b-57eb-a9a6-32bf5c50b686', 'cta', 4, 'cta_panel', '{"type":"cta_panel","_v":1,"kicker":"Prêt à gagner du temps ?","title":"Tout votre cabinet, réuni dans une seule application","lead":"Facturation, bilans, agenda, comptabilité et signature électronique — à partir de 24,84 €/mois, tout inclus.","primary":{"label":"Je m''abonne","href":"app:register:annual"},"secondary":{"label":"Demander une démo","href":"/contact"}}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('e17dc5f4-566d-5858-9895-89068dfc353c', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"badge":"Exclusivité MediCare Pro","title":"13 bilans podologiques normés, **scores calculés pour vous.**","lead":"Bilans cliniques complets, grilles validées et recommandations.\nAucun autre logiciel ne propose autant d''évaluations spécialisées."}'::jsonb),
  ('809c0a27-d991-588d-89d4-f2b48bd88fb6', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'showcase', 1, 'feature_showcase', '{"type":"feature_showcase","_v":1,"collection":"bilans","tones":["white","dark","soft"],"backgrounds":[{"index":1,"image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-4.jpg","alt":"Podologue évaluant un risque de chute"}}]}'::jsonb),
  ('37a6ad64-ca5d-5f49-8be3-225bc576f01a', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'benefits', 2, 'benefit_band', '{"type":"benefit_band","_v":1,"kicker":"Pourquoi ces bilans","title":"Des bilans conçus pour la clinique","items":[{"icon":"Calculator","title":"Scores calculés automatiquement","text":"Plus de calcul manuel : chaque grille produit son score instantanément."},{"icon":"BadgeCheck","title":"Grilles cliniques normées","text":"Des évaluations validées, conformes aux référentiels podologiques."},{"icon":"TrendingUp","title":"Suivi comparatif dans le temps","text":"Comparez les évaluations d''une consultation à l''autre, sans ressaisie."},{"icon":"FileText","title":"Rattaché au dossier patient","text":"Chaque bilan s''enregistre dans le dossier, prêt à l''export."}]}'::jsonb),
  ('ce5ab175-fe98-56bc-b1f3-b25558de6389', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'groups', 3, 'bilan_groups', '{"type":"bilan_groups","_v":1,"kicker":"La liste complète","title":"Les 13 bilans spécialisés","groups":[{"title":"Bilans d''examen clinique","items":[{"icon":"BadgeCheck","title":"Bilan statique","text":"Évaluation posturale complète : genu varum/valgum, scoliose, bassin, rachis."},{"icon":"Refresh","title":"Bilan dynamique","text":"Analyse de la marche, déroulé du pas, appui et propulsion."},{"icon":"Eye","title":"Bilan cutané / trophique","text":"État de la peau, lésions, hyperkératoses, mycoses, ongles."},{"icon":"CheckCircle","title":"Bilan vasculaire","text":"Pouls, IPS (index de pression systolique), signes d''insuffisance veineuse/artérielle."},{"icon":"User","title":"Examen morphologique du pied","text":"Forme du pied, hallux valgus, orteils en griffe, voûte plantaire."},{"icon":"FileText","title":"Bilan articulaire","text":"Mobilité hanche, genou, cheville, sous-talienne, métatarso-phalangienne."},{"icon":"Grid","title":"Bilan neurologique","text":"Monofilament, diapason, réflexes, proprioception, force motrice."},{"icon":"FileText","title":"Tests membres inférieurs","text":"Tests spécifiques du membre inférieur (Thomas, Ober, tiroir…)."}]},{"title":"Bilans spécifiques","items":[{"icon":"Eye","title":"Bilan posturologie","text":"Romberg, test unipodal, TUG, Fukuda, convergence oculaire, ATM, capteurs posturaux."},{"icon":"Clock","title":"Bilan sport","text":"Profil athlète, analyse biomécanique, proprioception, instabilité cheville, pression plantaire."},{"icon":"Info","title":"Bilan chutes","text":"7+ critères de risque, TUG, test unipodal, chair stand test, classification du risque."},{"icon":"Shield","title":"Bilan diabétique","text":"45+ champs : monofilament, IPS, grade de risque (0-3), auto-examen, recommandations."},{"icon":"User","title":"Bilan pédiatrie","text":"Foot Posture Index (FPI), genu valgum/varum, torsion tibiale, oculomotricité, marche."}]}]}'::jsonb),
  ('63eb7264-52c3-52fa-9b32-3369ab6cd8e6', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'steps', 4, 'timeline', '{"type":"timeline","_v":1,"kicker":"Comment ça marche","title":"Des scores calculés en 3 étapes","steps":[{"title":"Choisissez le bilan","text":"Sélectionnez le bilan normé adapté à votre patient parmi les 13 évaluations spécialisées intégrées."},{"title":"Saisissez vos observations","text":"Renseignez les items dans une interface claire, sans ressaisie. Tout est rattaché automatiquement au dossier patient."},{"title":"Obtenez le score automatiquement","text":"L''application calcule les scores normés instantanément et sécurise votre suivi dans le temps. Gagnez du temps à chaque consultation."}]}'::jsonb),
  ('87b71e14-8e2a-5240-9861-014deceb5e87', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'stats', 5, 'stats_band', '{"type":"stats_band","_v":1,"kicker":"En chiffres","title":"Des bilans qui font la différence","stats":[{"icon":"FileText","to":13,"suffix":"","label":"bilans podologiques inclus"},{"icon":"Calculator","to":45,"prefix":"+","suffix":"","label":"champs sur le bilan diabétique"},{"icon":"Refresh","to":100,"suffix":" %","label":"scores calculés automatiquement"},{"icon":"BadgeCheck","to":0,"suffix":" €","label":"de supplément, tout est inclus"}]}'::jsonb),
  ('83fd080d-4ad0-5ee9-9dbb-1ed940a06be4', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'cta', 6, 'cta_panel', '{"type":"cta_panel","_v":1,"kicker":"Tout inclus, sans option","title":"Les 13 bilans inclus dans votre abonnement","lead":"Scores calculés, grilles validées et suivi patient — à partir de 24,84 €/mois, sans supplément ni option payante.","primary":{"label":"Commencer maintenant","href":"app:register:annual"},"secondary":{"label":"Voir les tarifs","href":"/tarifs"}}'::jsonb),
  ('d7edd8bd-33e1-5584-87d3-3867da313abd', '7f3e147b-35f7-5152-a91a-2019cd67cded', 'cross_links', 7, 'cross_links', '{"type":"cross_links","_v":1,"links":[{"label":"Les avantages","href":"/avantages"},{"label":"Toutes les fonctionnalités","href":"/fonctionnalites"},{"label":"Sécurité & conformité","href":"/securite"}]}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('8e1e6481-b049-568a-9b66-bc5d839c8f0f', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Sécurité & conformité","title":"Vos données de santé, **protégées au plus haut niveau.**","lead":"Hébergement HDS chez OVHcloud en France, chiffrement de bout en bout et conformité RGPD : la confidentialité de vos patients, notre priorité absolue.","trust":[{"icon":"BadgeCheck","label":"Certifié HDS"},{"icon":"Shield","label":"Conforme RGPD"},{"icon":"Lock","label":"Chiffré de bout en bout"},{"icon":"Globe","label":"Données en France"}]}'::jsonb),
  ('78060b89-e7c2-5dc2-a666-841653f920f7', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'showcase_1', 1, 'showcase', '{"type":"showcase","_v":1,"icon":"Server","kicker":"Infrastructure","title":"Hébergement HDS en France","text":"Vos données de santé sont hébergées chez un prestataire certifié Hébergeur de Données de Santé (HDS), exclusivement sur le territoire français. Aucune donnée patient ne quitte la France.","points":["Certification HDS conforme à l''article L.1111-8 du Code de la santé publique","Datacenters situés sur le sol français","Redondance et haute disponibilité de l''infrastructure","Isolation stricte des environnements de production"],"image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section1.jpg","alt":"Baies de serveurs hébergeant les données de santé MediCare Pro"},"tone":"white","reverse":false}'::jsonb),
  ('690dcd95-e067-5c42-bc87-473410aa155d', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'showcase_2', 2, 'showcase', '{"type":"showcase","_v":1,"icon":"Globe","kicker":"Hébergeur","title":"Hébergé chez OVHcloud, datacenters en France","text":"Nous nous appuyons sur OVHcloud, leader européen du cloud et hébergeur certifié HDS. Vos données patients sont stockées dans ses datacenters français, sous souveraineté européenne — à l''abri des législations extra-européennes.","points":["OVHcloud : hébergeur certifié HDS et souveraineté européenne","Datacenters Tier III+ en France, sécurisés 24h/24","Aucune dépendance au Cloud Act américain","Engagement de réversibilité de vos données"],"image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section2.jpg","alt":"Couloir de datacenter OVHcloud hébergeant MediCare Pro"},"tone":"dark","reverse":true}'::jsonb),
  ('2b737957-aacb-5464-ace2-808350db40d4', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'showcase_3', 3, 'showcase', '{"type":"showcase","_v":1,"icon":"Lock","kicker":"Chiffrement","title":"Chiffrement de bout en bout","text":"Vos données sont chiffrées en transit et au repos. Les communications passent par des canaux TLS et le stockage est protégé par un chiffrement AES robuste : même en cas d''accès physique, les données restent illisibles.","points":["Chiffrement AES-256 des données au repos","Connexions chiffrées TLS 1.3 de bout en bout","Authentification forte pour bloquer tout accès non autorisé","Cloisonnement des accès par rôle (podologue, cabinet)"],"image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section3.jpg","alt":"Flux de données chiffrées illustré par du code binaire"},"tone":"soft","reverse":false}'::jsonb),
  ('8bbbe397-34d7-5a35-8f73-687b04f8c11a', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'showcase_4', 4, 'showcase', '{"type":"showcase","_v":1,"icon":"Shield","kicker":"Conformité","title":"Conformité RGPD & droits des patients","text":"Le traitement de vos données respecte le Règlement Général sur la Protection des Données : finalités déclarées, minimisation, consentement et respect intégral des droits des patients. Vous restez maître de vos données.","points":["Finalités de traitement déclarées et limitées","Droit d''accès, de rectification et d''effacement garantis","Registre des traitements tenu à jour","Sous-traitants conformes RGPD et localisés en Europe"],"image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section4.jpg","alt":"Conformité RGPD et souveraineté des données européennes"},"tone":"dark","reverse":true}'::jsonb),
  ('ed58683a-020f-5612-ab55-ae45e9d357cf', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'guarantees', 5, 'stats_band', '{"type":"stats_band","_v":1,"kicker":"Nos garanties","title":"La sécurité, mesurée et garantie","stats":[{"icon":"Server","to":99.9,"suffix":" %","decimals":1,"label":"de disponibilité garantie"},{"icon":"Key","to":256,"suffix":" bits","label":"de chiffrement AES des données"},{"icon":"Refresh","to":24,"suffix":" h","label":"fréquence des sauvegardes"},{"icon":"Globe","to":100,"suffix":" %","label":"des données hébergées en France"}]}'::jsonb),
  ('367875f0-dffd-5f53-8cce-19a69ce9f7dc', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'host', 6, 'host_band', '{"type":"host_band","_v":1,"kicker":"Infrastructure de confiance","title":"Un hébergement souverain, en qui vous pouvez avoir confiance","text":"MediCare Pro s''appuie sur OVHcloud, leader européen du cloud et acteur reconnu de l''hébergement de données de santé. Vos données patients restent en France, sous protection européenne.","points":["Hébergeur agréé pour les données de santé (HDS)","Souveraineté européenne — hors Cloud Act","Datacenters français sécurisés en continu"],"logoCaption":"Hébergeur certifié HDS"}'::jsonb),
  ('748a48dd-8323-5c65-ad1b-96947ee88a1e', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'portal', 7, 'portal_cards', '{"type":"portal_cards","_v":1,"kicker":"Aller plus loin","title":"Découvrir MediCare Pro","linkLabel":"Découvrir","cards":[{"icon":"FileText","title":"Toutes les fonctionnalités","text":"Facturation, signature, comptabilité, agenda, bilans et application mobile — tout votre cabinet réuni.","href":"/fonctionnalites"},{"icon":"CheckCircle","title":"Tarifs tout inclus","text":"Un seul abonnement, sans option cachée. Sécurité, mises à jour et support compris.","href":"/tarifs"},{"icon":"BadgeCheck","title":"Les 13 bilans podologiques","text":"Des bilans normés avec scores calculés automatiquement, pour un suivi patient sécurisé.","href":"/bilans"}]}'::jsonb),
  ('b20d8c29-df4f-5dfc-a05f-f3891bd695b4', 'a28928df-91ba-5680-9559-3aa314dc6f73', 'cta', 8, 'cta_panel', '{"type":"cta_panel","_v":1,"kicker":"Vos patients méritent le meilleur","title":"Vos données patients, entre de bonnes mains","lead":"Hébergement HDS en France, chiffrement de bout en bout et conformité RGPD — tout est inclus, à partir de 24,84 €/mois.","primary":{"label":"Je m''abonne","href":"app:register:annual"},"secondary":{"label":"Demander une démo","href":"/contact"}}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('26ec7a03-65f7-5ea3-be38-2bd711420ffb', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Avantages","title":"Un seul logiciel, **tout votre cabinet simplifié.**","lead":"Tout-en-un, simple, rapide et économique : voici pourquoi les podologues choisissent MediCare Pro pour gérer leur cabinet au quotidien — à partir de 24,84 €/mois, tout inclus.","trust":[{"icon":"Layers","label":"Tout-en-un"},{"icon":"Sparkles","label":"Simple à prendre en main"},{"icon":"Clock","label":"Gain de temps"},{"icon":"Wallet","label":"Jusqu''à 260 €/mois économisés"}]}'::jsonb),
  ('01c37eb5-fa1e-5cea-9422-1fa733385099', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'showcase_1', 1, 'showcase', '{"type":"showcase","_v":1,"icon":"Layers","kicker":"Tout-en-un","title":"Tout votre cabinet dans une seule application","text":"Fini les outils dispersés et les abonnements multiples. Patients, factures, comptabilité, agenda, bilans et signature : tout est réuni au même endroit, sans ressaisie.","points":["Patients, factures, compta et agenda centralisés","Aucune double saisie d''un outil à l''autre","Une seule facture mensuelle, un seul interlocuteur","10 fonctionnalités majeures incluses"],"mockup":"pwa","tone":"white","reverse":false}'::jsonb),
  ('7cd7350d-bb6e-591c-9bdc-7bbc19cce32e', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'showcase_2', 2, 'showcase', '{"type":"showcase","_v":1,"icon":"Sparkles","kicker":"Simplicité","title":"Une prise en main immédiate, sans formation","text":"Une interface claire, pensée pour les podologues et non pour les informaticiens. Vous êtes opérationnel dès le premier jour, sans manuel ni formation coûteuse.","points":["Interface intuitive et épurée","Opérationnel dès le premier jour","Aucune formation requise","Support humain réactif si besoin"],"mockup":"agenda","tone":"soft","reverse":true}'::jsonb),
  ('7961b356-f5de-5879-9f6d-c281087d6556', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'showcase_3', 3, 'showcase', '{"type":"showcase","_v":1,"icon":"Zap","kicker":"Gain de temps","title":"Des heures gagnées chaque semaine","text":"L''administratif tourne tout seul : factures générées automatiquement, scores de bilans calculés, rappels de rendez-vous envoyés. Vous vous concentrez sur vos patients.","points":["Facturation générée 100 % automatiquement","Scores et grades de bilans calculés","Rappels de rendez-vous par email et SMS","Beaucoup moins d''administratif au quotidien"],"image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-2.jpg","alt":"Podologue qui gagne du temps grâce à l''automatisation"},"tone":"dark","reverse":false}'::jsonb),
  ('b6b1ae17-436c-587f-a4c8-c6b8282ab57a', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'showcase_4', 4, 'showcase', '{"type":"showcase","_v":1,"icon":"FileText","kicker":"Cliniquement complet","title":"Les bilans les plus complets du marché","text":"13 bilans podologiques normés, du pied diabétique au risque de chute en passant par la posturologie, avec scores et grades calculés automatiquement pour un suivi fiable.","points":["13 bilans podologiques inclus","Scores et grades calculés automatiquement","Grilles cliniques validées","Suivi comparatif dans le temps"],"mockup":"bilan","tone":"white","reverse":true}'::jsonb),
  ('1eb45681-507e-5ebc-a137-56127ff14236', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'showcase_5', 5, 'showcase', '{"type":"showcase","_v":1,"icon":"ShieldCheck","kicker":"Confiance","title":"Vos données protégées au plus haut niveau","text":"Hébergement HDS en France chez OVHcloud, conformité RGPD, chiffrement de bout en bout et sauvegardes incluses : la sécurité de vos patients est garantie, sans surcoût.","points":["Hébergement HDS en France","Conformité RGPD","Chiffrement de bout en bout","Sauvegardes quotidiennes incluses"],"image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section1.jpg","alt":"Infrastructure sécurisée hébergeant les données MediCare Pro"},"tone":"dark","reverse":false}'::jsonb),
  ('34e59262-5fd2-5187-9cf3-e262b34236f4', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'savings', 6, 'savings_compare', '{"type":"savings_compare","_v":1,"kicker":"Économies réalisées","title":"Un seul abonnement, pas cinq factures","lead":"Un podologue dépense en moyenne 285 €/mois en outils séparés. MediCare Pro centralise tout à partir de 24,84 €/mois.","before":{"label":"Sans MediCare Pro","price":285,"priceNote":"/mois","totalLabel":"Total mensuel","tools":[{"icon":"Calendar","label":"Agenda & prise de RDV en ligne","price":"150 €"},{"icon":"Invoice","label":"Logiciel de facturation","price":"40 €"},{"icon":"Calculator","label":"Expert-comptable / comptabilité","price":"60 €"},{"icon":"Signature","label":"Signature électronique","price":"20 €"},{"icon":"Server","label":"Sauvegarde sécurisée","price":"15 €"}]},"after":{"label":"MediCare Pro","price":24.84,"priceNote":"/mois","badge":"Tout inclus","points":["Agenda et prise de RDV inclus","Comptabilité intégrée","Sans aucune option cachée"]},"stats":[{"icon":"TrendingUp","to":260,"prefix":"−","suffix":" €","label":"économisés par mois"},{"icon":"Wallet","to":3120,"suffix":" €","label":"économisés par an, en moyenne"}],"tone":"soft"}'::jsonb),
  ('1375ba15-1c2a-5151-8f3b-9e381fbab826', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'reviews', 7, 'reviews', '{"type":"reviews","_v":1,"kicker":"Avis de podologues","title":"Ils nous font confiance","tone":"white","rating":{"value":"4,9/5","label":"note moyenne · podologues abonnés"}}'::jsonb),
  ('5e4fa36b-de0e-5b23-91fd-f91a68f854ad', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'stats', 8, 'stats_band', '{"type":"stats_band","_v":1,"kicker":"En chiffres","title":"Le tout-en-un qui change la donne","stats":[{"icon":"TrendingUp","to":260,"prefix":"−","suffix":" €","label":"économisés par mois en moyenne"},{"icon":"Layers","to":10,"suffix":"","label":"fonctionnalités majeures incluses"},{"icon":"FileText","to":13,"suffix":"","label":"bilans podologiques inclus"},{"icon":"Wallet","to":3120,"suffix":" €","label":"économisés par an, en moyenne"}]}'::jsonb),
  ('e6b058ca-6246-5782-800b-636eaf42346d', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'portal', 9, 'portal_cards', '{"type":"portal_cards","_v":1,"kicker":"Aller plus loin","title":"Explorer MediCare Pro","linkLabel":"Découvrir","cards":[{"icon":"Layers","title":"Toutes les fonctionnalités","text":"Facturation, signature, comptabilité, agenda, bilans et application mobile — le détail de tout ce qui est inclus.","href":"/fonctionnalites","stat":"10 fonctionnalités"},{"icon":"Calculator","title":"Tarifs tout inclus","text":"Un seul abonnement à 24,84 €/mois, sans option cachée. Comparez et calculez vos économies.","href":"/tarifs","stat":"24,84 €/mois"},{"icon":"FileText","title":"Les 13 bilans podologiques","text":"Le catalogue de bilans le plus complet du marché, avec scores calculés automatiquement.","href":"/bilans","stat":"13 bilans"}]}'::jsonb),
  ('e6bcc3ee-cd70-5604-a05d-cbe4d5fd964a', '43ec57f2-2a17-5221-89d7-b5c3a9e3b2ae', 'cta', 10, 'cta_panel', '{"type":"cta_panel","_v":1,"kicker":"Prêt à simplifier votre cabinet ?","title":"Tout votre cabinet réuni, pour 24,84 €/mois","lead":"Tout-en-un, sans option cachée — et plus de 3 000 € économisés par an en moyenne face aux outils séparés.","primary":{"label":"Je m''abonne","href":"app:register:annual"},"secondary":{"label":"Demander une démo","href":"/contact"},"trust":[{"icon":"ShieldCheck","label":"Hébergé en France (HDS)"},{"icon":"Wallet","label":"Sans engagement"},{"icon":"Clock","label":"Opérationnel en 1 jour"}]}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('6602a0a1-2ff4-52bd-8ebc-40144b08c9c6', '255a8761-714c-50fa-ad7a-194723a4bcc7', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Tarifs","title":"Un prix unique, tout compris, sans surprise","lead":"Pas d''option payante, pas de module en supplément. Toutes les fonctionnalités incluses, à partir de 24,84 €/mois.","image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-4.jpg","alt":""}}'::jsonb),
  ('1229ecbe-d976-583a-8c2a-548f4f259098', '255a8761-714c-50fa-ad7a-194723a4bcc7', 'pricing', 1, 'pricing', '{"type":"pricing","_v":1,"title":"Une offre unique, **tout inclus**","subtitle":"Pas d''options payantes, pas de modules en supplément. Toutes les fonctionnalités sont incluses.","examplesTitle":"Exemples de tarification","tableHead":{"config":"Configuration","monthly":"Mensuel","yearly":"Annuel"},"navLinks":[{"label":"← Sécurité","href":"/securite"},{"label":"Les avantages →","href":"/avantages"},{"label":"Toutes les fonctionnalités →","href":"/fonctionnalites"}],"ctaBand":{"title":"Arrêtez de payer 285 €/mois pour 24,84 €","text":"Tout inclus. Économisez plus de 3 000 € par an.","cta":{"label":"Je m''abonne","href":"app:register:annual"},"note":"Offre 12 mois · 24,84 €/mois TTC"}}'::jsonb),
  ('581b0d5a-bea9-5434-b2fe-9eb0556bee96', '255a8761-714c-50fa-ad7a-194723a4bcc7', 'savings', 2, 'savings_compare', '{"type":"savings_compare","_v":1,"kicker":"Économies réalisées","title":"Combien coûte un logiciel de podologie ?","lead":"Un podologue dépense en moyenne 285 €/mois en outils séparés. MediCare Pro centralise tout à partir de 24,84 €/mois.","before":{"label":"Outils séparés","price":285,"priceNote":"/mois"},"after":{"label":"MediCare Pro, tout inclus","price":24.84,"priceNote":"/mois"},"result":"Soit **+3 000 € économisés par an**, en moyenne.","stats":[{"value":"−260 €","label":"par mois face aux outils séparés"},{"value":"−17 %","label":"sur l''offre 12 mois (60,48 €/an)"},{"value":"0 €","label":"d''option cachée — tout est inclus"}]}'::jsonb),
  ('0834cf4b-906c-503f-9b45-cbe858adfc4e', '255a8761-714c-50fa-ad7a-194723a4bcc7', 'faq', 3, 'faq', '{"type":"faq","_v":1,"kicker":"Questions fréquentes","title":"Vous vous demandez…"}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('bb54871f-4c40-59b0-86de-3eaf7cfdbf4d', '9bd47d97-093f-542c-ace8-0104077998d4', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Contact","title":"Parlons de votre cabinet","lead":"Une question, une démo, un abonnement ? Notre équipe vous répond. Hébergement HDS en France, données conformes RGPD.","image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-1.jpg","alt":""}}'::jsonb),
  ('e8fda5fd-ec5f-5a84-a5bb-caaee4a216a3', '9bd47d97-093f-542c-ace8-0104077998d4', 'channels', 1, 'contact_channels', '{"type":"contact_channels","_v":1,"kicker":"Nous écrire","title":"Une équipe qui connaît vos journées","text":"Une question sur les tarifs, la migration de vos données ou la conformité HDS ? Choisissez le canal qui vous arrange — on vous répond vite, et sans jargon.","channels":[{"icon":"Mail","title":"Par email","value":"contact@medicarepro.fr","note":"Réponse sous 24 h ouvrées","href":"mailto:contact@medicarepro.fr"},{"icon":"Phone","title":"Par téléphone","value":"01 23 45 67 89","note":"Du lundi au vendredi, 9 h – 18 h","href":"tel:+33123456789"},{"icon":"Headset","title":"Démo en visio","value":"30 minutes, sur vos cas concrets","note":"Gratuit et sans engagement"}],"hdsLine":"Vos données sont hébergées en France (HDS), chiffrées et conformes RGPD.","form":{"title":"Demander une démo","sub":"Dites-nous en un mot où en est votre cabinet, on s''occupe du reste.","consent":"J''accepte que mes données soient traitées conformément à la politique de confidentialité.","submitLabel":"Envoyer ma demande","successTitle":"Message bien reçu !","successText":"Merci pour votre confiance. Un membre de l''équipe revient vers vous sous 24 h ouvrées pour organiser la suite.","footNote":"Données hébergées en France (HDS), chiffrées et conformes RGPD."}}'::jsonb),
  ('f232cb38-e2cb-5b66-a273-5eefd0031465', '9bd47d97-093f-542c-ace8-0104077998d4', 'steps', 2, 'contact_steps', '{"type":"contact_steps","_v":1,"kicker":"Et ensuite ?","title":"De votre message à un cabinet équipé","steps":[{"title":"On vous répond","text":"Sous 24 h ouvrées, par email ou téléphone, selon votre préférence."},{"title":"On vous montre","text":"Une démo personnalisée de 30 minutes, sur les cas concrets de votre cabinet."},{"title":"Vous démarrez","text":"Import de vos données et cabinet opérationnel en une journée."}]}'::jsonb),
  ('47023df9-3430-540c-8c40-d03544963f9f', '9bd47d97-093f-542c-ace8-0104077998d4', 'cross_links', 3, 'cross_links', '{"type":"cross_links","_v":1,"links":[{"label":"Voir les tarifs","href":"/tarifs"},{"label":"Les fonctionnalités","href":"/fonctionnalites"},{"label":"Sécurité des données","href":"/securite"}]}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('cf667da8-b132-5014-a8a9-3cd49ecaf1b9', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"À propos","title":"Conçu par des podologues, pour des podologues","lead":"Notre mission : réunir tout ce dont un cabinet de podologie a besoin dans une seule application, simple et conforme.","image":{"mediaId":null,"path":"/images/bilans-cabinet.jpg","alt":""},"imagePos":"center 45%"}'::jsonb),
  ('a04199c6-9ca2-59f7-98cf-c1db66052b25', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'story', 1, 'story', '{"type":"story","_v":1,"kicker":"Notre histoire","title":"Né dans un cabinet, pas dans un open space.","paragraphs":["MediCare Pro est parti d''un constat simple : un podologue jongle en moyenne avec **quatre logiciels** — patients, agenda, facturation, comptabilité — pour près de **285 € par mois**. Des outils qui ne se parlent pas, et des heures d''administratif qui s''accumulent le soir.","Nous avons donc construit l''outil que nous aurions voulu trouver : **une seule application**, du dossier patient à la comptabilité, pensée pour les journées réelles d''un cabinet — pas pour une plaquette commerciale.","Chaque fonctionnalité est née d''une demande de praticien ; c''est encore comme ça que MediCare Pro évolue aujourd''hui."],"signature":"L''équipe MediCare Pro"}'::jsonb),
  ('0d8380d1-8842-5d8d-b590-448c90b961b9', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'timeline', 2, 'timeline', '{"type":"timeline","_v":1,"steps":[{"title":"Le constat","text":"Quatre logiciels, près de 285 € par mois, et des soirées entières perdues en paperasse : la gestion du cabinet grignote le temps de soin."},{"title":"Le déclic","text":"Plutôt que d''empiler un outil de plus, tout réunir dans une seule application pensée pour les journées réelles d''un podologue."},{"title":"Le produit","text":"Dossiers patients, 13 bilans normés, facturation, agenda et comptabilité prennent forme — testés en cabinet, pas en salle de réunion."},{"title":"Aujourd''hui","text":"Une communauté de podologues qui fait évoluer l''outil en continu, une fonctionnalité à la fois."}]}'::jsonb),
  ('67c661b1-93fe-510e-bf66-71670877e084', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'stats', 3, 'stats_band', '{"type":"stats_band","_v":1,"kicker":"En chiffres","title":"MediCare Pro aujourd''hui","stats":[{"icon":"FileText","to":13,"suffix":"","decimals":0,"label":"bilans podologiques normés, scores calculés automatiquement"},{"icon":"Wallet","to":3120,"suffix":" €","decimals":0,"label":"économisés par an en moyenne face aux outils séparés"},{"icon":"ShieldCheck","to":100,"suffix":" %","decimals":0,"label":"des données hébergées en France, certifié HDS"},{"icon":"Invoice","to":24.84,"suffix":" €","decimals":2,"label":"par mois tout compris, sans option cachée"}]}'::jsonb),
  ('1cef8da8-83fb-5fb5-a9cb-f7b67620d618', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'values', 4, 'values', '{"type":"values","_v":1,"kicker":"Nos engagements","title":"Pensé pour votre quotidien","items":[{"icon":"CheckCircle","title":"Simplicité","text":"Une prise en main immédiate, sans formation."},{"icon":"Grid","title":"Tout-en-un","text":"Patients, factures, compta, agenda : un seul outil."},{"icon":"ShieldCheck","title":"Conformité","text":"RGPD et données de santé hébergées en HDS."},{"icon":"Lock","title":"Sécurité","text":"Chiffrement complet, authentification forte."},{"icon":"Clock","title":"Gain de temps","text":"Facturation et bilans automatisés."}],"teaserHref":"/avantages"}'::jsonb),
  ('0cd6d7cd-7ec7-5dbc-a10e-e85906b3be69', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'reviews', 5, 'reviews', '{"type":"reviews","_v":1,"kicker":"Avis de podologues","title":"Ils nous font confiance","tone":"white","rating":{"value":"4,9/5","label":"note moyenne · podologues abonnés"}}'::jsonb),
  ('7481154a-c6c2-54be-aab0-639824c073dd', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'cross_links', 6, 'cross_links', '{"type":"cross_links","_v":1,"links":[{"label":"Les avantages","href":"/avantages"},{"label":"Sécurité des données","href":"/securite"},{"label":"Les bilans podologiques","href":"/bilans"}]}'::jsonb),
  ('debf788e-f4cc-5f96-8770-01583b4dadeb', '743597e5-3f46-5194-9ba2-80b4e0cf88dc', 'cta_band', 7, 'cta_band', '{"type":"cta_band","_v":1,"title":"Ne laissez plus l''administratif vous freiner","text":"Abonnez-vous dès aujourd''hui et centralisez tout votre cabinet.","cta":{"label":"Je m''abonne","href":"app:register:annual"},"tone":"soft"}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('7b83e260-be5f-5d12-9d50-0f4c7831397b', 'ed91e558-c140-508e-b290-cc09834550ce', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Informations légales","title":"Conditions générales d''utilisation","lead":"Les présentes conditions régissent l''utilisation du site vitrine medicarepro.fr.","image":{"mediaId":null,"path":"/images/fonctionnalites/podologue-medicarepro-section-2.jpg","alt":""}}'::jsonb),
  ('33f35068-a4f1-54ff-8706-63e473fb2012', 'ed91e558-c140-508e-b290-cc09834550ce', 'body', 1, 'rich_text', '{"type":"rich_text","_v":1,"body":{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"1. Objet"}]},{"type":"paragraph","content":[{"type":"text","text":"Les présentes conditions générales d''utilisation (CGU) encadrent l''accès et l''utilisation du site medicarepro.fr (le « Site »), édité par [À COMPLÉTER : raison sociale]. En naviguant sur le Site, l''utilisateur accepte les présentes CGU sans réserve."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"2. Description du service"}]},{"type":"paragraph","content":[{"type":"text","text":"Le Site est un site vitrine présentant MediCare Pro, logiciel de gestion de cabinet destiné aux pédicures-podologues : dossiers patients, facturation, comptabilité, agenda, bilans podologiques et signature électronique. La souscription à l''abonnement et l''utilisation du logiciel s''effectuent sur l''application dédiée (app.medicarepro.fr) et sont régies par des conditions contractuelles propres, communiquées lors de l''inscription."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"3. Accès au Site"}]},{"type":"paragraph","content":[{"type":"text","text":"Le Site est accessible gratuitement, 24 h/24 et 7 j/7, sous réserve des opérations de maintenance et des aléas techniques. L''éditeur ne saurait être tenu responsable d''une indisponibilité temporaire du Site."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"4. Propriété intellectuelle"}]},{"type":"paragraph","content":[{"type":"text","text":"Tous les éléments du Site (textes, visuels, logos, marque « MediCare Pro », interfaces) sont protégés par le droit de la propriété intellectuelle et demeurent la propriété exclusive de l''éditeur. Toute reproduction non autorisée constitue une contrefaçon."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"5. Responsabilité"}]},{"type":"paragraph","content":[{"type":"text","text":"Les informations publiées sur le Site (dont les contenus du blog à destination des professionnels) sont fournies à titre informatif et ne constituent ni un avis médical, ni un engagement contractuel. L''éditeur s''efforce d''assurer l''exactitude des informations mais ne peut la garantir de manière absolue."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"6. Liens externes"}]},{"type":"paragraph","content":[{"type":"text","text":"Le Site peut contenir des liens vers des sites tiers. L''éditeur n''exerce aucun contrôle sur ces sites et décline toute responsabilité quant à leur contenu."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"7. Données personnelles"}]},{"type":"paragraph","content":[{"type":"text","text":"Les traitements de données personnelles liés au Site sont décrits dans la "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/confidentialite"}}],"text":"politique de confidentialité"},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"8. Droit applicable"}]},{"type":"paragraph","content":[{"type":"text","text":"Les présentes CGU sont soumises au droit français. Tout litige relatif à leur interprétation ou leur exécution relève, à défaut de résolution amiable, de la compétence des tribunaux français."}]},{"type":"paragraph","content":[{"type":"text","text":"Dernière mise à jour : [À COMPLÉTER : date]."}]}]}}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('34b916ce-72d4-5161-a59b-60f3f15ea54d', 'f320f25b-b97e-5385-9f49-83c2f97fde92', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Informations légales","title":"Mentions légales","lead":"Informations relatives à l''éditeur et à l''hébergement du site medicarepro.fr.","image":{"mediaId":null,"path":"/images/about-app.jpg","alt":""}}'::jsonb),
  ('f6d92178-5d83-5a36-9137-4e218b8ecc64', 'f320f25b-b97e-5385-9f49-83c2f97fde92', 'body', 1, 'rich_text', '{"type":"rich_text","_v":1,"body":{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Éditeur du site"}]},{"type":"paragraph","content":[{"type":"text","text":"Le site medicarepro.fr est édité par [À COMPLÉTER : raison sociale], [À COMPLÉTER : forme juridique] au capital de [À COMPLÉTER] €, immatriculée au RCS de [À COMPLÉTER] sous le numéro [À COMPLÉTER : SIREN/SIRET], dont le siège social est situé [À COMPLÉTER : adresse complète]."}]},{"type":"paragraph","content":[{"type":"text","text":"Numéro de TVA intracommunautaire : [À COMPLÉTER]. Directeur de la publication : [À COMPLÉTER : nom du dirigeant]."}]},{"type":"paragraph","content":[{"type":"text","text":"Contact : "},{"type":"text","marks":[{"type":"link","attrs":{"href":"mailto:contact@medicarepro.fr"}}],"text":"contact@medicarepro.fr"},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Hébergement"}]},{"type":"paragraph","content":[{"type":"text","text":"Le site est hébergé par OVHcloud (OVH SAS), 2 rue Kellermann, 59100 Roubaix, France — téléphone : 1007 — "},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://www.ovhcloud.com","target":"_blank","rel":"noopener noreferrer"}}],"text":"www.ovhcloud.com"},{"type":"text","text":". Les données de santé traitées par l''application MediCare Pro sont hébergées en France chez un hébergeur certifié HDS (Hébergeur de Données de Santé)."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Propriété intellectuelle"}]},{"type":"paragraph","content":[{"type":"text","text":"L''ensemble des contenus du site (textes, visuels, logos, interfaces, marque « MediCare Pro ») est protégé par le droit de la propriété intellectuelle. Toute reproduction, représentation ou diffusion, totale ou partielle, sans autorisation écrite préalable de l''éditeur est interdite et constitue une contrefaçon sanctionnée par le Code de la propriété intellectuelle."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Données personnelles"}]},{"type":"paragraph","content":[{"type":"text","text":"Les traitements de données personnelles réalisés via ce site sont décrits dans notre "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/confidentialite"}}],"text":"politique de confidentialité"},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Droit applicable"}]},{"type":"paragraph","content":[{"type":"text","text":"Le présent site est soumis au droit français. En cas de litige, et à défaut de résolution amiable, les tribunaux français seront seuls compétents."}]}]}}'::jsonb);
insert into public.page_sections (id, page_id, section_key, position, type, content) values
  ('bf8198da-0c68-5f9e-8881-990bcf32bf76', 'e6bbefcf-145b-522a-8288-0fec8643a1df', 'hero', 0, 'page_hero', '{"type":"page_hero","_v":1,"kicker":"Informations légales","title":"Politique de confidentialité","lead":"Comment nous collectons, utilisons et protégeons vos données personnelles, conformément au RGPD.","image":{"mediaId":null,"path":"/images/securite/podologue-medicarepro-servers-section1.jpg","alt":""}}'::jsonb),
  ('0931fc46-916f-510d-8c24-5a65547c83aa', 'e6bbefcf-145b-522a-8288-0fec8643a1df', 'body', 1, 'rich_text', '{"type":"rich_text","_v":1,"body":{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"1. Responsable du traitement"}]},{"type":"paragraph","content":[{"type":"text","text":"Le responsable du traitement des données collectées via le site medicarepro.fr est [À COMPLÉTER : raison sociale], [À COMPLÉTER : adresse du siège]. Contact : "},{"type":"text","marks":[{"type":"link","attrs":{"href":"mailto:contact@medicarepro.fr"}}],"text":"contact@medicarepro.fr"},{"type":"text","text":"."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"2. Données collectées sur ce site"}]},{"type":"paragraph","content":[{"type":"text","text":"Le site vitrine collecte uniquement les données que vous nous transmettez volontairement via le formulaire de contact / demande de démonstration : nom, adresse email, numéro de téléphone, taille du cabinet et contenu de votre message."}]},{"type":"paragraph","content":[{"type":"text","text":"Le site vitrine ne collecte "},{"type":"text","marks":[{"type":"bold"}],"text":"aucune donnée de santé"},{"type":"text","text":". Les données de santé traitées par le logiciel MediCare Pro (application app.medicarepro.fr) font l''objet d''un traitement distinct, hébergé en France chez un hébergeur certifié HDS, et décrit dans les conditions propres à l''application."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"3. Finalités et bases légales"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Répondre à vos demandes de contact et de démonstration — base légale : mesures précontractuelles (art. 6.1.b RGPD)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Gestion de la relation commerciale et prospection auprès de professionnels — base légale : intérêt légitime (art. 6.1.f RGPD)."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"4. Durées de conservation"}]},{"type":"paragraph","content":[{"type":"text","text":"Les données issues du formulaire de contact sont conservées au maximum 3 ans à compter du dernier échange, puis supprimées ou anonymisées."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"5. Destinataires et sous-traitants"}]},{"type":"paragraph","content":[{"type":"text","text":"Les données sont destinées exclusivement à l''équipe MediCare Pro. Elles sont hébergées en France par OVHcloud (OVH SAS, 2 rue Kellermann, 59100 Roubaix). Aucune donnée n''est vendue ni transférée hors de l''Union européenne."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"6. Vos droits"}]},{"type":"paragraph","content":[{"type":"text","text":"Conformément au RGPD et à la loi Informatique et Libertés, vous disposez des droits d''accès, de rectification, d''effacement, de limitation, d''opposition et de portabilité sur vos données. Pour les exercer, écrivez-nous à "},{"type":"text","marks":[{"type":"link","attrs":{"href":"mailto:contact@medicarepro.fr"}}],"text":"contact@medicarepro.fr"},{"type":"text","text":". Vous pouvez également introduire une réclamation auprès de la CNIL ("},{"type":"text","marks":[{"type":"link","attrs":{"href":"https://www.cnil.fr","target":"_blank","rel":"noopener noreferrer"}}],"text":"www.cnil.fr"},{"type":"text","text":")."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"7. Cookies"}]},{"type":"paragraph","content":[{"type":"text","text":"Le site n''utilise pas de cookies publicitaires ni de traceurs tiers. Seuls des cookies techniques strictement nécessaires au fonctionnement du site peuvent être déposés ; ils ne requièrent pas de consentement. Si des outils de mesure d''audience venaient à être ajoutés, cette politique serait mise à jour et votre consentement recueilli le cas échéant."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"8. Sécurité"}]},{"type":"paragraph","content":[{"type":"text","text":"Nous mettons en œuvre des mesures techniques et organisationnelles adaptées : chiffrement des échanges (TLS), hébergement en France, contrôle des accès et sauvegardes régulières. Pour en savoir plus, consultez notre page "},{"type":"text","marks":[{"type":"link","attrs":{"href":"/securite"}}],"text":"Sécurité"},{"type":"text","text":"."}]},{"type":"paragraph","content":[{"type":"text","text":"Dernière mise à jour : [À COMPLÉTER : date]."}]}]}}'::jsonb);
insert into public.posts (id, slug, title, excerpt, cover_media_id, cover_alt, status, published_at, reading_time_min, body, body_legacy, origin) values
  ('bd8b14d3-7c95-59c0-96b8-2424fb40f971', 'pied-diabetique-suivi', 'Pied du diabétique : les bons réflexes de suivi', 'Gradation du risque, monofilament, IPS, fréquence de suivi : les réflexes essentiels pour un suivi rigoureux du pied diabétique en cabinet.', 'db2cdb8f-b03b-571f-8106-475ed0141b2f', 'Examen podologique d''un pied diabétique en cabinet', 'published', '2026-06-12 09:00:00+02', 6, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Le pied diabétique reste l''une des complications les plus redoutées du diabète : on estime qu''un patient diabétique sur quatre développera une plaie du pied au cours de sa vie, et qu''une amputation liée au diabète survient toutes les vingt secondes dans le monde. Pourtant, la grande majorité de ces complications sont évitables grâce à un dépistage précoce et un suivi podologique structuré."}]},{"type":"paragraph","content":[{"type":"text","text":"Pour le pédicure-podologue, l''enjeu est double : identifier tôt les patients à risque grâce à une gradation rigoureuse, et assurer une traçabilité irréprochable du suivi dans le temps. Voici les réflexes essentiels à systématiser en cabinet."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"La gradation du risque, socle du suivi"}]},{"type":"paragraph","content":[{"type":"text","text":"La classification internationale gradue le risque podologique de 0 à 3. Elle conditionne à la fois la fréquence de suivi recommandée et la prise en charge par l''Assurance Maladie des séances de prévention."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Grade 0 : absence de neuropathie sensitive — examen annuel de dépistage."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Grade 1 : neuropathie sensitive isolée — bilan et surveillance au moins une fois par an."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Grade 2 : neuropathie associée à une artériopathie ou une déformation du pied — suivi renforcé, séances de prévention prises en charge."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Grade 3 : antécédent d''ulcération ou d''amputation — suivi rapproché et coordination étroite avec l''équipe de diabétologie."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Monofilament, IPS, pouls : le trio de l''examen"}]},{"type":"paragraph","content":[{"type":"text","text":"Le test au monofilament de 10 g reste l''examen de référence pour dépister la neuropathie sensitive. Appliqué sur des zones plantaires codifiées (pulpe du gros orteil, têtes métatarsiennes), il doit être réalisé dans le calme, en évitant les zones hyperkératosiques qui faussent la perception."}]},{"type":"paragraph","content":[{"type":"text","text":"L''évaluation vasculaire complète l''examen neurologique : palpation des pouls pédieux et tibiaux postérieurs, et mesure de l''IPS (index de pression systolique) lorsque l''artériopathie est suspectée. Un IPS inférieur à 0,9 oriente vers une artériopathie oblitérante des membres inférieurs et justifie un avis vasculaire."}]},{"type":"paragraph","content":[{"type":"text","text":"L''inspection cutanée et morphologique termine le bilan : hyperkératoses, fissures, mycoses, déformations (hallux valgus, orteils en griffe), points d''hyperappui — autant de portes d''entrée potentielles pour une plaie."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Éduquer le patient : l''auto-examen quotidien"}]},{"type":"paragraph","content":[{"type":"text","text":"Le meilleur suivi en cabinet ne remplace pas la vigilance quotidienne du patient. L''éducation thérapeutique fait partie intégrante de la consultation : inspection quotidienne des pieds (au besoin avec un miroir), séchage soigneux entre les orteils, chaussage adapté vérifié de la main avant l''enfilage, et consultation rapide au moindre signe d''alerte (rougeur, ampoule, plaie qui ne cicatrise pas)."}]},{"type":"paragraph","content":[{"type":"text","text":"Remettre au patient une fiche de conseils personnalisée, adaptée à son grade de risque, augmente sensiblement l''observance de ces gestes simples."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Tracer chaque bilan pour objectiver l''évolution"}]},{"type":"paragraph","content":[{"type":"text","text":"Le suivi du pied diabétique s''inscrit dans la durée : c''est la comparaison des bilans successifs qui révèle une dégradation débutante — perte progressive de sensibilité, baisse de l''IPS, apparition d''une déformation. Un bilan normé, daté et rattaché au dossier patient est donc indispensable."}]},{"type":"paragraph","content":[{"type":"text","text":"C''est précisément ce que propose MediCare Pro : un bilan du pied diabétique de plus de 45 champs guidés, avec calcul automatique du grade de risque, recommandations générées et comparaison d''une consultation à l''autre. Le podologue se concentre sur l''examen clinique, l''application s''occupe du score et de la traçabilité."}]}]}'::jsonb, '[{"paragraphs":["Le pied diabétique reste l''une des complications les plus redoutées du diabète : on estime qu''un patient diabétique sur quatre développera une plaie du pied au cours de sa vie, et qu''une amputation liée au diabète survient toutes les vingt secondes dans le monde. Pourtant, la grande majorité de ces complications sont évitables grâce à un dépistage précoce et un suivi podologique structuré.","Pour le pédicure-podologue, l''enjeu est double : identifier tôt les patients à risque grâce à une gradation rigoureuse, et assurer une traçabilité irréprochable du suivi dans le temps. Voici les réflexes essentiels à systématiser en cabinet."]},{"heading":"La gradation du risque, socle du suivi","paragraphs":["La classification internationale gradue le risque podologique de 0 à 3. Elle conditionne à la fois la fréquence de suivi recommandée et la prise en charge par l''Assurance Maladie des séances de prévention."],"list":["Grade 0 : absence de neuropathie sensitive — examen annuel de dépistage.","Grade 1 : neuropathie sensitive isolée — bilan et surveillance au moins une fois par an.","Grade 2 : neuropathie associée à une artériopathie ou une déformation du pied — suivi renforcé, séances de prévention prises en charge.","Grade 3 : antécédent d''ulcération ou d''amputation — suivi rapproché et coordination étroite avec l''équipe de diabétologie."]},{"heading":"Monofilament, IPS, pouls : le trio de l''examen","paragraphs":["Le test au monofilament de 10 g reste l''examen de référence pour dépister la neuropathie sensitive. Appliqué sur des zones plantaires codifiées (pulpe du gros orteil, têtes métatarsiennes), il doit être réalisé dans le calme, en évitant les zones hyperkératosiques qui faussent la perception.","L''évaluation vasculaire complète l''examen neurologique : palpation des pouls pédieux et tibiaux postérieurs, et mesure de l''IPS (index de pression systolique) lorsque l''artériopathie est suspectée. Un IPS inférieur à 0,9 oriente vers une artériopathie oblitérante des membres inférieurs et justifie un avis vasculaire.","L''inspection cutanée et morphologique termine le bilan : hyperkératoses, fissures, mycoses, déformations (hallux valgus, orteils en griffe), points d''hyperappui — autant de portes d''entrée potentielles pour une plaie."]},{"heading":"Éduquer le patient : l''auto-examen quotidien","paragraphs":["Le meilleur suivi en cabinet ne remplace pas la vigilance quotidienne du patient. L''éducation thérapeutique fait partie intégrante de la consultation : inspection quotidienne des pieds (au besoin avec un miroir), séchage soigneux entre les orteils, chaussage adapté vérifié de la main avant l''enfilage, et consultation rapide au moindre signe d''alerte (rougeur, ampoule, plaie qui ne cicatrise pas).","Remettre au patient une fiche de conseils personnalisée, adaptée à son grade de risque, augmente sensiblement l''observance de ces gestes simples."]},{"heading":"Tracer chaque bilan pour objectiver l''évolution","paragraphs":["Le suivi du pied diabétique s''inscrit dans la durée : c''est la comparaison des bilans successifs qui révèle une dégradation débutante — perte progressive de sensibilité, baisse de l''IPS, apparition d''une déformation. Un bilan normé, daté et rattaché au dossier patient est donc indispensable.","C''est précisément ce que propose MediCare Pro : un bilan du pied diabétique de plus de 45 champs guidés, avec calcul automatique du grade de risque, recommandations générées et comparaison d''une consultation à l''autre. Le podologue se concentre sur l''examen clinique, l''application s''occupe du score et de la traçabilité."]}]'::jsonb, 'manual'),
  ('a1031fb0-b93c-53e4-a77a-3ddf54d54d56', 'bien-choisir-ortheses-plantaires', 'Bien choisir ses orthèses plantaires', 'Indications, examen préalable, matériaux et suivi : la démarche complète pour concevoir des orthèses plantaires réellement efficaces.', '81fd8f00-c9fc-580a-93c6-73f9812f7c94', 'Orthèses plantaires sur mesure en cours de fabrication', 'published', '2026-06-05 09:00:00+02', 5, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"L''orthèse plantaire est l''un des outils thérapeutiques majeurs du pédicure-podologue. Bien indiquée et bien conçue, elle soulage les douleurs, corrige ou compense un trouble statique et prévient les récidives. Mal indiquée, elle déçoit le patient et discrédite le traitement."}]},{"type":"paragraph","content":[{"type":"text","text":"La différence se joue rarement sur le matériau seul : elle se joue sur la rigueur de l''examen clinique préalable et sur la qualité du suivi. Retour sur la démarche complète."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Tout part de l''examen clinique"}]},{"type":"paragraph","content":[{"type":"text","text":"Avant de penser correction, il faut objectiver le trouble. L''examen statique évalue les appuis, l''alignement de l''arrière-pied, la hauteur de l''arche médiale et les éventuelles inégalités de longueur des membres inférieurs. L''examen dynamique analyse le déroulé du pas : phase taligrade, plantigrade, digitigrade, comportement de l''arrière-pied en charge."}]},{"type":"paragraph","content":[{"type":"text","text":"Les tests spécifiques complètent l''analyse — mobilité de la première colonne, test de Jack, examen articulaire de la cheville et de la sous-talienne. Ce bilan initial, consigné précisément, servira de référence pour mesurer l''efficacité de l''appareillage."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Corriger, compenser ou amortir : trois logiques"}]},{"type":"paragraph","content":[{"type":"text","text":"Le choix de l''orthèse découle de l''objectif thérapeutique. On distingue schématiquement trois logiques, souvent combinées :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Correction : réaligner une articulation réductible (ex. contrôle du valgus calcanéen chez un pied plat souple)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Compensation : accommoder une déformation fixée ou une inégalité de longueur, en répartissant les contraintes."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Amortissement et décharge : soulager une zone d''hyperappui douloureuse (métatarsalgies, talalgies) par des matériaux absorbants et des évidements ciblés."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Matériaux et fabrication : adapter au patient, pas l''inverse"}]},{"type":"paragraph","content":[{"type":"text","text":"Résines thermoformables, EVA de différentes densités, éléments collés sur support : chaque technique a ses indications. Un sportif recherchera dynamisme et faible encombrement dans la chaussure ; un patient âgé ou diabétique privilégiera l''accommodation et la protection cutanée ; un enfant nécessitera un appareillage évolutif, réévalué à chaque poussée de croissance."}]},{"type":"paragraph","content":[{"type":"text","text":"Le chaussage du patient fait partie intégrante de la prescription : la meilleure orthèse du monde ne corrige rien dans une chaussure inadaptée. Ce point mérite d''être abordé explicitement en consultation."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Le suivi, clé de l''efficacité"}]},{"type":"paragraph","content":[{"type":"text","text":"Une orthèse se contrôle : à un mois pour vérifier la tolérance et l''adaptation, puis à chaque renouvellement (en général tous les ans, plus fréquemment chez l''enfant). La comparaison avec le bilan initial objectivera les progrès — diminution de la douleur, amélioration du déroulé du pas — et orientera les ajustements."}]},{"type":"paragraph","content":[{"type":"text","text":"Avec MediCare Pro, l''examen morphostatique, les tests dynamiques et les prescriptions d''orthèses sont consignés dans des bilans normés rattachés au dossier patient. À chaque contrôle, le podologue compare les évaluations en un clin d''œil, et la facturation de l''appareillage est générée automatiquement."}]}]}'::jsonb, '[{"paragraphs":["L''orthèse plantaire est l''un des outils thérapeutiques majeurs du pédicure-podologue. Bien indiquée et bien conçue, elle soulage les douleurs, corrige ou compense un trouble statique et prévient les récidives. Mal indiquée, elle déçoit le patient et discrédite le traitement.","La différence se joue rarement sur le matériau seul : elle se joue sur la rigueur de l''examen clinique préalable et sur la qualité du suivi. Retour sur la démarche complète."]},{"heading":"Tout part de l''examen clinique","paragraphs":["Avant de penser correction, il faut objectiver le trouble. L''examen statique évalue les appuis, l''alignement de l''arrière-pied, la hauteur de l''arche médiale et les éventuelles inégalités de longueur des membres inférieurs. L''examen dynamique analyse le déroulé du pas : phase taligrade, plantigrade, digitigrade, comportement de l''arrière-pied en charge.","Les tests spécifiques complètent l''analyse — mobilité de la première colonne, test de Jack, examen articulaire de la cheville et de la sous-talienne. Ce bilan initial, consigné précisément, servira de référence pour mesurer l''efficacité de l''appareillage."]},{"heading":"Corriger, compenser ou amortir : trois logiques","paragraphs":["Le choix de l''orthèse découle de l''objectif thérapeutique. On distingue schématiquement trois logiques, souvent combinées :"],"list":["Correction : réaligner une articulation réductible (ex. contrôle du valgus calcanéen chez un pied plat souple).","Compensation : accommoder une déformation fixée ou une inégalité de longueur, en répartissant les contraintes.","Amortissement et décharge : soulager une zone d''hyperappui douloureuse (métatarsalgies, talalgies) par des matériaux absorbants et des évidements ciblés."]},{"heading":"Matériaux et fabrication : adapter au patient, pas l''inverse","paragraphs":["Résines thermoformables, EVA de différentes densités, éléments collés sur support : chaque technique a ses indications. Un sportif recherchera dynamisme et faible encombrement dans la chaussure ; un patient âgé ou diabétique privilégiera l''accommodation et la protection cutanée ; un enfant nécessitera un appareillage évolutif, réévalué à chaque poussée de croissance.","Le chaussage du patient fait partie intégrante de la prescription : la meilleure orthèse du monde ne corrige rien dans une chaussure inadaptée. Ce point mérite d''être abordé explicitement en consultation."]},{"heading":"Le suivi, clé de l''efficacité","paragraphs":["Une orthèse se contrôle : à un mois pour vérifier la tolérance et l''adaptation, puis à chaque renouvellement (en général tous les ans, plus fréquemment chez l''enfant). La comparaison avec le bilan initial objectivera les progrès — diminution de la douleur, amélioration du déroulé du pas — et orientera les ajustements.","Avec MediCare Pro, l''examen morphostatique, les tests dynamiques et les prescriptions d''orthèses sont consignés dans des bilans normés rattachés au dossier patient. À chaque contrôle, le podologue compare les évaluations en un clin d''œil, et la facturation de l''appareillage est générée automatiquement."]}]'::jsonb, 'manual'),
  ('75cbf4bf-8897-5855-9883-79e19c12cdf3', 'posturologie-comprendre-le-bilan', 'Posturologie : comprendre le bilan', 'Capteurs posturaux, Romberg, Fukuda, convergence oculaire : ce que mesure réellement un bilan postural et comment l''interpréter.', '2914496a-5519-5fcc-bfdb-23d22896c2ea', 'Bilan postural d''un patient en cabinet de podologie', 'published', '2026-05-28 09:00:00+02', 6, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"La posturologie étudie la façon dont le corps se stabilise debout, en intégrant les informations de plusieurs « capteurs » : le pied, l''œil, l''appareil manducateur (ATM), la peau et l''oreille interne. Lorsqu''un de ces capteurs délivre une information erronée, le système postural compense — parfois au prix de douleurs chroniques : lombalgies, cervicalgies, tendinopathies récidivantes."}]},{"type":"paragraph","content":[{"type":"text","text":"Le pédicure-podologue, spécialiste du capteur podal, est souvent en première ligne pour dépister un syndrome de déficience posturale. Encore faut-il un bilan structuré et reproductible. Voici ce qu''il doit contenir."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"L''interrogatoire : chercher les signes d''appel"}]},{"type":"paragraph","content":[{"type":"text","text":"Douleurs rachidiennes chroniques sans cause retrouvée, instabilité, chutes à répétition, fatigue visuelle, céphalées, bruxisme : le faisceau d''arguments cliniques oriente vers une origine posturale. L''historique des traitements (orthèses antérieures, orthodontie, rééducation orthoptique) complète le tableau et guide l''examen."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Les tests posturaux de référence"}]},{"type":"paragraph","content":[{"type":"text","text":"Le bilan postural s''appuie sur une batterie de tests standardisés, réalisés dans des conditions reproductibles (même éclairage, mêmes consignes, pieds nus) :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Test de Romberg postural : oscillations et déviations du corps, yeux ouverts puis fermés — il oriente vers l''origine du trouble (visuelle, podale, vestibulaire)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Test de piétinement de Fukuda : 50 pas sur place, yeux fermés ; une rotation supérieure à 30° signe une asymétrie tonique."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Appui unipodal : stabilité comparée droite/gauche, indicateur simple et sensible."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Convergence oculaire : un défaut de convergence est l''une des causes les plus fréquentes de trouble postural — il justifie un adressage orthoptique."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Examen de l''ATM : ouverture buccale, déviations, claquements — en lien avec l''occlusion dentaire."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Interpréter : hiérarchiser les capteurs"}]},{"type":"paragraph","content":[{"type":"text","text":"L''objectif du bilan n''est pas d''accumuler les tests, mais de hiérarchiser : le capteur podal est-il causal, adaptatif ou mixte ? Les manœuvres de neutralisation (mousse sous les pieds, yeux fermés) permettent de faire la part des choses. Un trouble postural d''origine podale répondra aux orthèses posturales à éléments fins ; un trouble d''origine oculaire relève d''abord de l''orthoptiste, en coordination avec le podologue."}]},{"type":"paragraph","content":[{"type":"text","text":"Cette démarche pluridisciplinaire est la marque d''une posturologie sérieuse : le podologue traite ce qui relève du pied, et adresse ce qui n''en relève pas."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Un bilan normé pour un suivi objectif"}]},{"type":"paragraph","content":[{"type":"text","text":"La difficulté classique du bilan postural est sa reproductibilité : sans grille standardisée, difficile de comparer deux évaluations à six mois d''intervalle et d''objectiver l''effet des orthèses posturales."}]},{"type":"paragraph","content":[{"type":"text","text":"MediCare Pro intègre une grille posturale validée, prête à l''emploi : Romberg, Fukuda, appui unipodal, convergence, ATM et capteurs y sont consignés de façon structurée, avec un suivi comparatif automatique d''une consultation à l''autre. Le praticien gagne du temps de saisie et fiabilise son suivi."}]}]}'::jsonb, '[{"paragraphs":["La posturologie étudie la façon dont le corps se stabilise debout, en intégrant les informations de plusieurs « capteurs » : le pied, l''œil, l''appareil manducateur (ATM), la peau et l''oreille interne. Lorsqu''un de ces capteurs délivre une information erronée, le système postural compense — parfois au prix de douleurs chroniques : lombalgies, cervicalgies, tendinopathies récidivantes.","Le pédicure-podologue, spécialiste du capteur podal, est souvent en première ligne pour dépister un syndrome de déficience posturale. Encore faut-il un bilan structuré et reproductible. Voici ce qu''il doit contenir."]},{"heading":"L''interrogatoire : chercher les signes d''appel","paragraphs":["Douleurs rachidiennes chroniques sans cause retrouvée, instabilité, chutes à répétition, fatigue visuelle, céphalées, bruxisme : le faisceau d''arguments cliniques oriente vers une origine posturale. L''historique des traitements (orthèses antérieures, orthodontie, rééducation orthoptique) complète le tableau et guide l''examen."]},{"heading":"Les tests posturaux de référence","paragraphs":["Le bilan postural s''appuie sur une batterie de tests standardisés, réalisés dans des conditions reproductibles (même éclairage, mêmes consignes, pieds nus) :"],"list":["Test de Romberg postural : oscillations et déviations du corps, yeux ouverts puis fermés — il oriente vers l''origine du trouble (visuelle, podale, vestibulaire).","Test de piétinement de Fukuda : 50 pas sur place, yeux fermés ; une rotation supérieure à 30° signe une asymétrie tonique.","Appui unipodal : stabilité comparée droite/gauche, indicateur simple et sensible.","Convergence oculaire : un défaut de convergence est l''une des causes les plus fréquentes de trouble postural — il justifie un adressage orthoptique.","Examen de l''ATM : ouverture buccale, déviations, claquements — en lien avec l''occlusion dentaire."]},{"heading":"Interpréter : hiérarchiser les capteurs","paragraphs":["L''objectif du bilan n''est pas d''accumuler les tests, mais de hiérarchiser : le capteur podal est-il causal, adaptatif ou mixte ? Les manœuvres de neutralisation (mousse sous les pieds, yeux fermés) permettent de faire la part des choses. Un trouble postural d''origine podale répondra aux orthèses posturales à éléments fins ; un trouble d''origine oculaire relève d''abord de l''orthoptiste, en coordination avec le podologue.","Cette démarche pluridisciplinaire est la marque d''une posturologie sérieuse : le podologue traite ce qui relève du pied, et adresse ce qui n''en relève pas."]},{"heading":"Un bilan normé pour un suivi objectif","paragraphs":["La difficulté classique du bilan postural est sa reproductibilité : sans grille standardisée, difficile de comparer deux évaluations à six mois d''intervalle et d''objectiver l''effet des orthèses posturales.","MediCare Pro intègre une grille posturale validée, prête à l''emploi : Romberg, Fukuda, appui unipodal, convergence, ATM et capteurs y sont consignés de façon structurée, avec un suivi comparatif automatique d''une consultation à l''autre. Le praticien gagne du temps de saisie et fiabilise son suivi."]}]'::jsonb, 'manual');
insert into public.testimonials (id, name, role, avatar_media_id, avatar_path, quote, rating, position, published) values
  ('bff638da-ef53-53c8-9064-3ebd314984d1', 'Camille Besson', 'Podologue · Lyon', '626cb9d7-8b11-521f-9e23-bbae442c11c4', '/images/avatars/av1.jpg', 'J''ai enfin un seul outil pour tout : dossiers, bilans, factures. La facturation automatisée me fait gagner un temps fou, et savoir que tout est hébergé en HDS me rassure vraiment.', 5, 0, true),
  ('8256dabd-91d9-5a6f-8b2b-94a94687ca49', 'Antoine Rivière', 'Pédicure-podologue · Bordeaux', 'cbe99ae6-cfc8-51ba-990f-7090c1010793', '/images/avatars/av2.jpg', 'La signature électronique et la comptabilité intégrée ont supprimé mes allers-retours entre logiciels. Tout est centralisé, c''est limpide.', 5, 1, true),
  ('12938816-c0ab-596a-930d-4aaf1c6c1f7b', 'Sarah Lemoine', 'Podologue · Lille', '73881169-7986-53e4-97e5-907b1a7b16f9', '/images/avatars/av3.jpg', 'Les bilans avec scores calculés automatiquement sont un vrai plus pour le suivi. Et le prix unique sans option cachée, ça change tout.', 5, 2, true),
  ('70cee413-e89c-53d1-8aa3-f21f5a24f5d1', 'Julien Moreau', 'Podologue · Nantes', '78001ee3-0562-52c0-976a-da910b86bc04', '/images/avatars/av4.jpg', 'Je suis passé de quatre logiciels à un seul. Mes soirées de paperasse ont tout simplement disparu.', 5, 3, true),
  ('e72a7708-94ff-5beb-b635-b245457a3605', 'Léa Fontaine', 'Pédicure-podologue · Toulouse', 'ebfe27fb-c88a-55c3-a90d-f032dd4934fc', '/images/avatars/av5.jpg', 'L''agenda en ligne a divisé mes appels par deux : les patients réservent seuls, je me concentre sur les soins.', 5, 4, true),
  ('ffb073b5-4399-5744-8d8d-a30aa340737e', 'Marc Dubois', 'Podologue · Strasbourg', '9104222b-b55a-56b3-acea-0cc93ff0232d', '/images/avatars/av6.jpg', 'Hébergement HDS en France et prix unique transparent : exactement ce que je cherchais pour mon cabinet.', 5, 5, true);
insert into public.faq_items (id, question, answer, context, position, published) values
  ('be1d9491-ad76-59cf-9748-83bbb19ad1ac', 'Mes données patients sont-elles sécurisées ?', 'Oui. Hébergement certifié HDS en France, chiffrement complet, authentification forte et sauvegardes quotidiennes.', 'global', 0, true),
  ('8c101082-8bee-5999-bde5-a6d0b1c34397', 'Y a-t-il un engagement ?', 'L''offre Sans Engagement est résiliable à tout moment (préavis 15 jours). L''offre 12 mois ferme vous fait économiser environ 17 % (soit 60,48 €/an).', 'global', 1, true),
  ('99369fa4-e534-5876-9cd6-fde890d0c59d', 'Puis-je migrer depuis mon ancien logiciel ?', 'Oui, nous vous accompagnons dans la reprise et l''import de vos données existantes.', 'global', 2, true),
  ('c8ccb735-e695-5889-b021-f3a686fb41e5', 'Le logiciel fonctionne-t-il sur mobile ?', 'Oui, via une application PWA installable sur mobile et tablette, accessible partout.', 'global', 3, true),
  ('219cac27-298c-5164-90e4-17cdf69cde78', 'Y a-t-il des options payantes cachées ?', 'Non, tout est inclus. Seul un collaborateur supplémentaire (praticien) est facturé +15,00 € TTC/mois. Le service secrétariat (planning + admin) est gratuit.', 'global', 4, true);
insert into public.pricing_plans (id, plan_key, name, sub, price, unit, secondary, featured, badge, cta_label, features, position, published) values
  ('f2b6cd71-a895-5434-9588-3e7a5096db6e', 'monthly', 'Sans engagement', 'Liberté totale', 29.88, 'TTC/mois', 'soit 24,90 € HT/mois', false, null, 'Choisir cette offre', '[{"label":"Toutes les fonctionnalités incluses"},{"label":"1 praticien titulaire inclus"},{"label":"Résiliable à tout moment (préavis 15 jours)"},{"label":"Service secrétariat inclus (gratuit)"},{"label":"+15,00 € TTC/mois par collaborateur"},{"label":"Mises à jour incluses"}]'::jsonb, 0, true),
  ('e35e26ce-b611-5c05-90d9-f98305bf358b', 'annual', 'Offre 12 mois', 'Engagement 12 mois ferme', 24.84, 'TTC/mois', 'soit 20,70 € HT/mois — 298,08 € TTC/an', true, '−17 % recommandé', 'Choisir cette offre', '[{"label":"Toutes les fonctionnalités incluses"},{"label":"1 praticien titulaire inclus"},{"label":"Économisez 60,48 €/an","highlight":true},{"label":"Service secrétariat inclus (gratuit)"},{"label":"+15,00 € TTC/mois par collaborateur"},{"label":"Mises à jour incluses"}]'::jsonb, 1, true);
