insert into public.feature_items (id, collection, icon, kicker, title, text, points, mockup, href, href_label, position, published) values
  ('885197e6-bd64-55e7-b653-4661800fe938', 'features', 'Invoice', 'Facturation', 'Facturation 100 % automatique', 'Vos factures sont générées automatiquement à chaque acte. Numérotation légale, TVA, mentions obligatoires et envoi au patient. Zéro ressaisie, zéro oubli.', '["Génération auto à la consultation","Numérotation séquentielle conforme","Relances et suivi des impayés","Export comptable en un clic"]'::jsonb, 'invoice', null, null, 0, true),
  ('0730d516-e37b-5c09-b985-c915476fb478', 'features', 'Signature', 'Signature', 'Signature électronique eIDAS', 'Faites signer consentements et documents avec une signature électronique à valeur juridique (règlement eIDAS). Horodatée, archivée et opposable.', '["Valeur juridique (eIDAS)","Horodatage certifié","Archivage à valeur probante","Signature à distance"]'::jsonb, 'signature', null, null, 1, true),
  ('e6091342-6a65-5b4a-a4e9-f71dd7366115', 'features', 'Calculator', 'Comptabilité', 'Comptabilité : remplacez votre comptable', 'Tenez votre comptabilité sans expert. Export FEC, CSV et PDF, plan comptable général (PCG) mappé automatiquement, journaux et grand livre prêts pour votre AGA.', '["Export FEC, CSV et PDF","Mapping PCG automatique","Journaux & grand livre","Capitaux propres en temps réel"]'::jsonb, 'accounting', null, null, 2, true),
  ('e5ced570-26b0-5d8a-9bbd-e70c9b66548a', 'features', 'Calendar', 'Agenda', 'Agenda intégré : fini Doctolib à 150 €/mois', 'Un agenda complet inclus : prise de rendez-vous en ligne, rappels email et SMS automatiques (J-7, J-2), synchronisation et gestion multi-praticien.', '["Prise de RDV en ligne","Rappels email / SMS (J-7, J-2)","Moins de rendez-vous manqués","Inclus, sans surcoût"]'::jsonb, 'agenda', null, null, 3, true),
  ('bd3d392d-97a6-5d41-b815-3058d5b36b62', 'features', 'FileText', 'Bilans', '13 bilans podologiques normés', 'Des bilans cliniques complets avec scores calculés automatiquement, grilles validées et recommandations : diabétique, chutes, posturologie, pédiatrie, sport…', '["Scores calculés automatiquement","Grilles cliniques validées","Recommandations intégrées","13 bilans spécialisés inclus"]'::jsonb, 'bilan', '/bilans', 'Découvrir les 13 bilans', 4, true),
  ('0e2bf535-daaa-54be-9fd2-c5a4ce5ae30d', 'features', 'Smartphone', 'Mobilité', 'App mobile (PWA) + scan de documents', 'Installez MediCare Pro sur mobile et tablette (PWA) et travaillez partout. Auto-sauvegarde en temps réel et scan de documents directement à la caméra.', '["Installable (PWA)","Auto-sauvegarde temps réel","Scan caméra / webcam","Accessible partout"]'::jsonb, 'pwa', null, null, 5, true),
  ('71317772-1629-51b9-b8be-a396f96fafd8', 'features', 'ShieldPlus', 'SESAM-Vitale', 'Carte Vitale & télétransmission', 'Lisez la carte Vitale et l''ApCV, sécurisez l''identité du patient et préparez la télétransmission. Solution agréée CNDA, intégrée à votre flux de soins.', '["Lecture carte Vitale & ApCV","Agrément CNDA","Identité patient sécurisée","Prêt pour la télétransmission"]'::jsonb, 'vitale', null, null, 6, true),
  ('117ec521-6810-565d-a953-0bc54e07250c', 'features', 'Star', 'Intelligence artificielle', 'Comptes-rendus assistés par IA', 'Dictez ou saisissez vos observations, l''IA rédige un compte-rendu clair et structuré en quelques secondes. Vous gardez la main, vous gagnez du temps.', '["Rédaction automatique structurée","Gain de temps à chaque consultation","Vous validez et ajustez","Données de santé protégées"]'::jsonb, 'ai', null, null, 7, true),
  ('4468e6fe-aca0-5916-ae40-2352e0828a77', 'features', 'Users', 'Portail patient', 'Un espace dédié à vos patients', 'Vos patients prennent rendez-vous en ligne, accèdent à leurs documents et échangent avec vous en toute sécurité, depuis leur propre espace.', '["Prise de rendez-vous en ligne","Accès aux documents","Messagerie sécurisée","Moins d''appels au cabinet"]'::jsonb, 'portal', null, null, 8, true),
  ('a0032270-fad9-5f4f-afc4-89b7bc1251d5', 'features', 'Monitor', 'Pilotage', 'Statistiques, traçabilité & multi-cabinet', 'Pilotez votre activité avec des statistiques claires, assurez la traçabilité (matériovigilance) et gérez plusieurs cabinets et collaborateurs depuis un seul compte.', '["Tableau de bord statistiques","Traçabilité & matériovigilance","Multi-cabinet & collaborateurs","Vue d''ensemble en temps réel"]'::jsonb, 'stats', null, null, 9, true),
  ('9b55cfad-fb87-5c34-9c97-ff52b39e99d1', 'bilans', 'ShieldPlus', 'Le plus complet', 'Le bilan du pied diabétique, complet', 'Plus de 45 champs guidés : monofilament, IPS, gradation du risque (0-3), auto-examen et recommandations. Le grade de risque est calculé automatiquement pour sécuriser votre suivi et tracer chaque évaluation.', '["Grade de risque (0-3) calculé automatiquement","Monofilament, IPS et pouls intégrés","Auto-examen et conseils patient générés","Comparaison du suivi dans le temps"]'::jsonb, 'bilan', null, null, 0, true),
  ('520e3fca-3e8c-5374-abf8-43d6d5abf30b', 'bilans', 'Star', 'Prévention', 'Évaluez le risque de chute en quelques clics', '7+ critères de risque, TUG, test unipodal, chair stand test : l''application classe automatiquement le niveau de risque pour orienter votre prise en charge et repérer tôt les patients fragiles.', '["7+ critères de risque pondérés","TUG, test unipodal & chair stand test","Classification automatique du risque","Repérage précoce des patients fragiles"]'::jsonb, 'bilanChute', null, null, 1, true),
  ('b1afdae7-74e3-57d2-aacd-f6000ebbf2d4', 'bilans', 'FileText', 'Grille validée', 'Une grille posturale validée, prête à l''emploi', 'Romberg, test unipodal, TUG, Fukuda, convergence oculaire, ATM, capteurs posturaux : tous les items normés réunis dans une interface claire, sans ressaisie, rattachés au dossier patient.', '["Tous les items normés réunis","Capteurs posturaux & ATM","Convergence oculaire & oculomotricité","Saisie guidée, sans ressaisie"]'::jsonb, 'bilanPosturo', null, null, 2, true);
