  ('jsonld_software', '{"@type":"SoftwareApplication","@id":"https://medicarepro.fr/#software","name":"MediCare Pro","applicationCategory":"BusinessApplication","operatingSystem":"Web","url":"https://medicarepro.fr","description":"Logiciel de gestion de cabinet pour podologues : dossiers patients, facturation automatique, agenda, 13 bilans podologiques, comptabilité et signature électronique. Hébergement HDS en France.","offers":{"@type":"Offer","price":"24.84","priceCurrency":"EUR","description":"Abonnement mensuel TTC (offre 12 mois), tout inclus."},"publisher":{"@id":"https://medicarepro.fr/#organization"},"inLanguage":"fr-FR"}'::jsonb, true),
