insert into public.seo_meta (id, path, title, title_absolute, description, canonical, sitemap_include, sitemap_priority, sitemap_changefreq) values
  ('87af2bd3-61ce-5f1c-bba8-99e67c93dc8c', '/', 'MediCare Pro — Logiciel tout-en-un pour podologues', true, 'Dossiers patients, facturation automatique, agenda, 13 bilans et comptabilité : tout votre cabinet de podologie dans une seule application, dès 24,84 €/mois.', '/', true, 1.0, 'weekly'),
  ('a98db7bc-d984-5985-aa32-01db529ac020', '/fonctionnalites', 'Fonctionnalités du logiciel podologue', false, 'Toutes les fonctionnalités de MediCare Pro : facturation automatique, signature électronique eIDAS, comptabilité, agenda intégré, 13 bilans podologiques et application mobile (PWA).', '/fonctionnalites', true, 0.8, 'monthly'),
  ('bfcec0f4-ac74-5722-bb3f-11a035635055', '/bilans', 'Logiciel de bilan podologique — 13 bilans spécialisés', false, '13 bilans podologiques normés, scores calculés automatiquement : diabétique, chutes, posturologie, pédiatrie et plus. Tout inclus dans l''abonnement.', '/bilans', true, 0.8, 'monthly'),
  ('19ee7e93-c61c-5f19-b072-33536e039b37', '/securite', 'Sécurité et conformité des données de santé', false, 'Hébergement HDS chez OVHcloud en France, conformité RGPD, chiffrement de bout en bout et sauvegardes quotidiennes : vos données patients sont protégées.', '/securite', true, 0.8, 'monthly'),
  ('6d185269-3bf1-5ab4-a877-ac4e95d121ca', '/avantages', 'Les avantages du logiciel tout-en-un', false, 'Tout-en-un, simple, rapide : pourquoi les podologues choisissent MediCare Pro. Jusqu''à 260 €/mois économisés vs des outils séparés, dès 24,84 €/mois.', '/avantages', true, 0.8, 'monthly'),
  ('64ee5ff9-dc5c-5fbd-b0e6-59d5034210fa', '/tarifs', 'Tarifs', false, 'Une offre unique tout inclus : sans engagement à 29,88 € TTC/mois ou offre 12 mois à 24,84 € TTC/mois (−17 %). Service secrétariat gratuit, conforme HDS et RGPD.', '/tarifs', true, 0.8, 'monthly'),
  ('2dcc09f0-aba4-5ee6-8180-c3a222cf3b65', '/a-propos', 'À propos', false, 'MediCare Pro, le logiciel de gestion de cabinet conçu par et pour les podologues. Notre mission : centraliser tout votre cabinet dans une seule application.', '/a-propos', true, 0.6, 'monthly'),
  ('d15a3bdb-3d2a-5d8b-85ed-69b8c03621af', '/blog', 'Blog', false, 'Conseils et actualités pour les podologues : suivi du pied diabétique, orthèses plantaires, posturologie et bonnes pratiques de cabinet.', '/blog', true, 0.6, 'weekly'),
  ('d2e55243-bfe5-5641-ad91-521b80d79b13', '/contact', 'Contact', false, 'Contactez MediCare Pro pour vous abonner ou demander une démonstration. Hébergement HDS en France, données chiffrées et conformes RGPD.', '/contact', true, 0.6, 'monthly'),
  ('f6730b9f-f865-5b10-b1ee-ba7d96b6184b', '/mentions-legales', 'Mentions légales', false, 'Mentions légales du site medicarepro.fr : éditeur, directeur de la publication, hébergement et propriété intellectuelle.', '/mentions-legales', true, 0.2, 'yearly'),
  ('1cec71d8-0a1d-52d5-8fcc-5bc97ad8dbc1', '/cgu', 'Conditions générales d''utilisation', false, 'Conditions générales d''utilisation du site medicarepro.fr : accès au site, propriété intellectuelle, responsabilité et données personnelles.', '/cgu', true, 0.2, 'yearly'),
  ('e7ab5ad4-d1a9-54a5-92b6-490b3c47bb79', '/confidentialite', 'Politique de confidentialité', false, 'Politique de confidentialité de medicarepro.fr : données collectées, finalités, durées de conservation, hébergement HDS et droits RGPD.', '/confidentialite', true, 0.2, 'yearly'),
  ('35a3370a-0698-5e50-9d91-42738ccd264e', '/blog/pied-diabetique-suivi', 'Pied du diabétique : les bons réflexes de suivi', false, 'Gradation du risque, monofilament, IPS, fréquence de suivi : les réflexes essentiels pour un suivi rigoureux du pied diabétique en cabinet.', '/blog/pied-diabetique-suivi', true, 0.5, 'yearly'),
  ('7a177b74-ad22-5a7b-bc79-d5050303900d', '/blog/bien-choisir-ortheses-plantaires', 'Bien choisir ses orthèses plantaires', false, 'Indications, examen préalable, matériaux et suivi : la démarche complète pour concevoir des orthèses plantaires réellement efficaces.', '/blog/bien-choisir-ortheses-plantaires', true, 0.5, 'yearly'),
  ('9b2796da-3e3c-51be-b092-22c02af27703', '/blog/posturologie-comprendre-le-bilan', 'Posturologie : comprendre le bilan', false, 'Capteurs posturaux, Romberg, Fukuda, convergence oculaire : ce que mesure réellement un bilan postural et comment l''interpréter.', '/blog/posturologie-comprendre-le-bilan', true, 0.5, 'yearly');
